function solve(prices: number[], strategy: number[], k: number): number {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit without any modification
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    maxProfit = originalProfit;

    // Try all possible continuous k-length subarrays to modify
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit if we modify the subarray [i, i + k - 1]
        let modifiedProfit = originalProfit;

        // Calculate the difference caused by the modification
        // Original strategy in the subarray: first k/2 elements are -1, next k/2 are 1
        // We need to change the first k/2 elements from their original values to 0
        // And the next k/2 elements from their original values to 1
        for (let j = 0; j < k; j++) {
            const originalValue = strategy[i + j];
            if (j < k / 2) {
                // Change from -1 to 0
                modifiedProfit += (0 - originalValue) * prices[i + j];
            } else {
                // Change from 1 to 1 (no change) or from 0 to 1
                // So we need to check if originalValue is 0 and change to 1
                if (originalValue === 0) {
                    modifiedProfit += (1 - originalValue) * prices[i + j];
                }
            }
        }

        // Update maxProfit if this modification gives a higher profit
        maxProfit = Math.max(maxProfit, modifiedProfit);
    }

    return maxProfit;
}

